import{_ as r,r as n,o as a,c as o,b as e,d as i,a as s,e as l}from"./app.0a43b3c6.js";const d={},c=s('<h1 id="render-and-commit" tabindex="-1"><a class="header-anchor" href="#render-and-commit" aria-hidden="true">#</a> Render and Commit</h1><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview" aria-hidden="true">#</a> Overview</h2><ul><li>Before your components are displayed on screen, they must be rendered by React.</li><li>This process of requesting and serving UI has three steps: <ol><li>Triggering a render</li><li>Rendering the component</li><li>Committing to the DOM</li></ol></li></ul><h2 id="step-1-trigger-a-render" tabindex="-1"><a class="header-anchor" href="#step-1-trigger-a-render" aria-hidden="true">#</a> Step 1: Trigger a render</h2><ul><li>There are two reasons for a component to render: <ul><li>It\u2019s the component\u2019s initial render.</li><li>The component\u2019s (or one of its ancestors\u2019) state has been updated.</li></ul></li></ul><h2 id="step-2-react-renders-your-components" tabindex="-1"><a class="header-anchor" href="#step-2-react-renders-your-components" aria-hidden="true">#</a> Step 2: React renders your components</h2><ul><li>\u201CRendering\u201D is React calling your components. <ul><li>On initial render, React will call the root component.</li><li>For subsequent renders, React will call the function component whose state update triggered the render.</li></ul></li><li>This process is recursive: if the updated component returns some other component, React will render that component next, and if that component also returns something, it will render that component next, and so on. The process will continue until there are no more nested components and React knows exactly what should be displayed on screen.</li></ul><h2 id="step-3-react-commits-changes-to-the-dom" tabindex="-1"><a class="header-anchor" href="#step-3-react-commits-changes-to-the-dom" aria-hidden="true">#</a> Step 3: React commits changes to the DOM</h2><ul><li>After rendering (calling) your components, React will modify the DOM. <ul><li>For the initial render, React will use the <code>appendChild()</code> DOM API to put all the DOM nodes it has created on screen.</li><li>For re-renders, React will apply the minimal necessary operations (calculated while rendering!) to make the DOM match the latest rendering output.</li></ul></li></ul><h2 id="refs" tabindex="-1"><a class="header-anchor" href="#refs" aria-hidden="true">#</a> Refs</h2>',10),h={href:"https://beta.reactjs.org/learn/render-and-commit",target:"_blank",rel:"noopener noreferrer"},m=l("Render and Commit");function u(p,f){const t=n("ExternalLinkIcon");return a(),o("div",null,[c,e("ul",null,[e("li",null,[e("a",h,[m,i(t)])])])])}const _=r(d,[["render",u],["__file","render_and_commit.html.vue"]]);export{_ as default};
